import{c as e,Q as i,j as n,m as s}from"./chunks/framework.Bhbi9jCp.js";const u=JSON.parse('{"title":"iOS 证书、私钥、Provisioning Profile 与 Archive","description":"","frontmatter":{},"headers":[],"relativePath":"mobileCommonLearning/06-iOS证书私钥ProvisioningProfile与Archive.md","filePath":"mobileCommonLearning/06-iOS证书私钥ProvisioningProfile与Archive.md","lastUpdated":1780912084000}'),t={name:"mobileCommonLearning/06-iOS证书私钥ProvisioningProfile与Archive.md"};function p(l,a,o,r,d,c){return i(),n("div",null,[...a[0]||(a[0]=[s(`<h1 id="ios-证书、私钥、provisioning-profile-与-archive" tabindex="-1">iOS 证书、私钥、Provisioning Profile 与 Archive <a class="header-anchor" href="#ios-证书、私钥、provisioning-profile-与-archive" aria-label="Permalink to &quot;iOS 证书、私钥、Provisioning Profile 与 Archive&quot;">​</a></h1><p>iOS 签名看起来复杂,但核心就一句:账号证明你属于哪个 Team,证书和私钥证明你能签,profile 证明这个 App 可以用哪些能力。</p><p>一句话先记住:<strong>iOS 签名 = Team + Bundle ID + certificate/private key + provisioning profile + entitlements。</strong></p><hr><h2 id="一、几个材料" tabindex="-1">一、几个材料 <a class="header-anchor" href="#一、几个材料" aria-label="Permalink to &quot;一、几个材料&quot;">​</a></h2><table tabindex="0"><thead><tr><th>材料</th><th>作用</th></tr></thead><tbody><tr><td>Apple Developer Account</td><td>开发者账号和团队</td></tr><tr><td>Team ID</td><td>团队身份</td></tr><tr><td>Bundle ID / App ID</td><td>App 身份</td></tr><tr><td>Certificate</td><td>Apple 签发的证书</td></tr><tr><td>Private Key</td><td>本机生成的私钥</td></tr><tr><td><code>.p12</code></td><td>证书 + 私钥导出</td></tr><tr><td>Provisioning Profile</td><td>App、证书、设备、能力、分发方式的组合</td></tr><tr><td>Entitlements</td><td>App 声明的系统能力</td></tr></tbody></table><p>真正能签名的是:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>certificate + private key</span></span></code></pre></div><p>只有 <code>.cer</code> 没有私钥,不能签。</p><hr><h2 id="二、provisioning-profile" tabindex="-1">二、Provisioning Profile <a class="header-anchor" href="#二、provisioning-profile" aria-label="Permalink to &quot;二、Provisioning Profile&quot;">​</a></h2><p>Profile 约束:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>哪个 App ID</span></span>
<span class="line"><span>哪个 Team</span></span>
<span class="line"><span>哪些 certificates</span></span>
<span class="line"><span>哪些 devices(开发 / Ad Hoc)</span></span>
<span class="line"><span>哪些 entitlements</span></span>
<span class="line"><span>哪种 distribution</span></span></code></pre></div><p>常见类型:</p><table tabindex="0"><thead><tr><th>类型</th><th>用途</th></tr></thead><tbody><tr><td>Development</td><td>开发调试</td></tr><tr><td>Ad Hoc</td><td>指定设备分发</td></tr><tr><td>App Store</td><td>上传 App Store / TestFlight</td></tr><tr><td>Enterprise</td><td>企业内部分发</td></tr></tbody></table><p>App Store 场景不需要绑定设备 UDID。</p><hr><h2 id="三、entitlements" tabindex="-1">三、Entitlements <a class="header-anchor" href="#三、entitlements" aria-label="Permalink to &quot;三、Entitlements&quot;">​</a></h2><p>Entitlements 是能力声明:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Push Notifications</span></span>
<span class="line"><span>Associated Domains</span></span>
<span class="line"><span>App Groups</span></span>
<span class="line"><span>iCloud</span></span>
<span class="line"><span>Sign in with Apple</span></span>
<span class="line"><span>Keychain Sharing</span></span>
<span class="line"><span>Background Modes</span></span></code></pre></div><p>必须同时满足:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>项目里声明</span></span>
<span class="line"><span>Apple Developer 后台启用</span></span>
<span class="line"><span>Provisioning Profile 包含</span></span></code></pre></div><p>三者不一致,就会出现:</p><ul><li>Archive 失败</li><li>上传失败</li><li>能上传但线上能力不工作</li></ul><hr><h2 id="四、换-mac-能不能继续发版" tabindex="-1">四、换 Mac 能不能继续发版 <a class="header-anchor" href="#四、换-mac-能不能继续发版" aria-label="Permalink to &quot;四、换 Mac 能不能继续发版&quot;">​</a></h2><p>App Store 场景通常可以。</p><p>条件:</p><ul><li>有 Apple Developer Team 权限</li><li>能访问 App Store Connect 里的 App</li><li>Bundle ID 一致</li><li>使用同一 Team 的有效 Distribution 证书和 App Store profile</li><li>build number 高于线上</li><li>capabilities 配置一致</li></ul><p>不必须:</p><ul><li>原来的 Mac</li><li>旧私钥</li><li>旧 <code>.p12</code></li></ul><p>但 CI/CD 或手动签名场景仍建议迁移 <code>.p12</code> 和 profile。</p><hr><h2 id="五、xcode-自动签名" tabindex="-1">五、Xcode 自动签名 <a class="header-anchor" href="#五、xcode-自动签名" aria-label="Permalink to &quot;五、Xcode 自动签名&quot;">​</a></h2><p>适合个人和小团队:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Xcode 登录 Apple ID</span></span>
<span class="line"><span>选择 Team</span></span>
<span class="line"><span>Automatically manage signing</span></span>
<span class="line"><span>Xcode 自动创建 / 下载 profile</span></span>
<span class="line"><span>Archive</span></span></code></pre></div><p>优点:</p><ul><li>简单</li><li>本地开发少踩坑</li><li>profile 自动更新</li></ul><p>缺点:</p><ul><li>CI 不稳定</li><li>多 target / extension 时不够可控</li><li>团队协作不容易审计</li></ul><p>生产 CI 推荐明确管理证书和 profile。</p><hr><h2 id="六、archive" tabindex="-1">六、Archive <a class="header-anchor" href="#六、archive" aria-label="Permalink to &quot;六、Archive&quot;">​</a></h2><p>Xcode Archive 产物:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>.xcarchive</span></span>
<span class="line"><span>  Products/Applications/App.app</span></span>
<span class="line"><span>  dSYMs/</span></span>
<span class="line"><span>  Info.plist</span></span></code></pre></div><p>Archive 后可以:</p><ul><li>上传 App Store Connect</li><li>导出 IPA</li><li>分发 TestFlight</li><li>提取 dSYM</li></ul><p>每次发布都要保留对应 dSYM,否则 crash 不能符号化。</p><hr><h2 id="七、多-target" tabindex="-1">七、多 Target <a class="header-anchor" href="#七、多-target" aria-label="Permalink to &quot;七、多 Target&quot;">​</a></h2><p>这些通常都有自己的 Bundle ID:</p><ul><li>主 App</li><li>Notification Service Extension</li><li>Widget Extension</li><li>Watch App</li><li>Share Extension</li></ul><p>每个 target 都要匹配:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Bundle ID</span></span>
<span class="line"><span>profile</span></span>
<span class="line"><span>entitlements</span></span>
<span class="line"><span>capabilities</span></span></code></pre></div><p>不要只检查 Runner / App 主 target。</p><hr><h2 id="八、什么时候会出事故" tabindex="-1">八、什么时候会出事故 <a class="header-anchor" href="#八、什么时候会出事故" aria-label="Permalink to &quot;八、什么时候会出事故&quot;">​</a></h2><ol><li>导入 <code>.cer</code> 但没有私钥,签名身份不可用。</li><li>profile 过期,CI 突然不能打包。</li><li>Associated Domains 在 entitlements 里有,但 profile 没包含。</li><li>Widget target 用错 Team 或 Bundle ID。</li><li>build number 没递增,上传失败。</li><li>dSYM 没保存,线上 crash 无法符号化。</li></ol><hr><h2 id="九、检查清单" tabindex="-1">九、检查清单 <a class="header-anchor" href="#九、检查清单" aria-label="Permalink to &quot;九、检查清单&quot;">​</a></h2><ul><li>[ ] Bundle ID 是否和线上一致</li><li>[ ] Team 是否正确</li><li>[ ] Distribution certificate 是否有私钥</li><li>[ ] profile 是否匹配 App Store / Ad Hoc / Enterprise 场景</li><li>[ ] entitlements 是否和后台 capabilities 一致</li><li>[ ] extension target 是否逐个检查</li><li>[ ] build number 是否递增</li><li>[ ] dSYM 是否归档并上传</li><li>[ ] CI 是否能在干净机器签名</li></ul><hr><h2 id="十、心智模型" tabindex="-1">十、心智模型 <a class="header-anchor" href="#十、心智模型" aria-label="Permalink to &quot;十、心智模型&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>账号决定 Team</span></span>
<span class="line"><span>Bundle ID 决定 App</span></span>
<span class="line"><span>证书 + 私钥决定能不能签</span></span>
<span class="line"><span>Profile 决定能签什么能力和分发方式</span></span>
<span class="line"><span>Archive 是发布前的正式产物</span></span></code></pre></div><p>下一篇 07 讲签名资产备份、迁移、丢失与泄漏应急。</p>`,65)])])}const g=e(t,[["render",p]]);export{u as __pageData,g as default};
